def calculate_cycle_deviation(tsm_util, samsung_util, avg_inventory_days):
    # Normalize inputs to percentages/decimals
    avg_cap_util = (tsm_util + samsung_util) / 2
    # Calculate deviation: (Capacity Utilization - Inventory Normalization Proxy) / Inventory Proxy
    # Assuming inventory_days is inversely proportional to demand absorption
    inventory_norm = max(0, (180 - avg_inventory_days) / 180) 
    deviation = avg_cap_util - inventory_norm

    if deviation > 0.05:
        signal = 'OVERHEATING / SUPPLY CONSTRAINT'
    elif deviation < -0.05:
        signal = 'OVERSUPPLY / DEMAND WEAKNESS'
    else:
        signal = 'BALANCED / CYCLE INFLECTION'

